def match_parens(lst):
    def is_good(s):
        balance = 0
        for char in s:
            if char == '(':
                balance += 1
            else:
                balance -= 1
            if balance < 0:
                return False
        return balance == 0

    a, b = lst[0], lst[1]

    # Check if either order of concatenation results in a good string
    return 'Yes' if is_good(a + b) or is_good(b + a) else 'No'

# Examples
print(match_parens(['()(', ')']))  # Expected output: 'Yes'
print(match_parens([')', ')']))     # Expected output: 'No'
```
